```typescript
// Escuchar eventos del Web Component
export class AppointmentsComponent {
  onAppointmentBooked(event: CustomEvent) {
    const appointment = event.detail;
    console.log('Cita reservada:', appointment);

    // Actualizar estado de la app
    this.store.dispatch(AppointmentActions.addAppointment({
      appointment: appointment.data
    }));

    // Mostrar notificación
    this.toastService.success('Cita reservada correctamente');
  }

  onError(event: CustomEvent) {
    const error = event.detail;
    console.error('Error en el componente:', error);

    this.toastService.error(error.message);
  }
}
