### Formulario de Perfil

```typescript
// Container
@Component({
  selector: 'app-profile-container',
  template: `
    <app-profile-form
      [initialData]="userData$ | async"
      [saving]="saving$ | async"
      (submit)="onSubmit($event)"
      (cancel)="onCancel()">
    </app-profile-form>
  `
})
export class ProfileContainerComponent {
  userData$ = this.store.select(selectUserData);
  saving$ = this.store.select(selectIsSaving);

  onSubmit(formData: UserData) {
    this.store.dispatch(UserActions.updateProfile({ formData }));
  }

  onCancel() {
    this.router.navigate(['/dashboard']);
  }
}

// Presenter
@Component({
  selector: 'app-profile-form',
  changeDetection: ChangeDetectionStrategy.OnPush
})
export class ProfileFormComponent implements OnChanges {
  @Input() initialData: UserData | null = null;
  @Input() saving = false;

  @Output() submit = new EventEmitter<UserData>();
  @Output() cancel = new EventEmitter<void>();

  form: FormGroup;

  ngOnChanges(changes: SimpleChanges) {
    if (changes['initialData'] && this.initialData) {
      this.form.patchValue(this.initialData);
    }
  }

  onSubmit() {
    if (this.form.valid) {
      this.submit.emit(this.form.value);
    }
  }
}
```

