## Best Practices

### 1. Normalizar el Estado

```typescript
// ❌ Mal: Datos anidados
interface BadState {
  users: {
    id: string;
    posts: Post[];
  }[];
}

// ✅ Bien: Estado normalizado
interface GoodState {
  users: { [id: string]: User };
  posts: { [id: string]: Post };
}
```

### 2. Keep Reducers Pure

```typescript
// ❌ Mal: Mutando el estado
on(addItem, (state, { item }) => {
  state.items.push(item); // NUNCA mutar
  return state;
});

// ✅ Bien: Inmutabilidad
on(addItem, (state, { item }) => ({
  ...state,
  items: [...state.items, item]
}));
```

### 3. Usar Entity Adapter

```typescript
import { createEntityAdapter, EntityState } from '@ngrx/entity';

export interface UserState extends EntityState<User> {
  selectedUserId: string | null;
}

export const userAdapter = createEntityAdapter<User>();

const initialState: UserState = userAdapter.getInitialState({
  selectedUserId: null
});

export const userReducer = createReducer(
  initialState,
  on(UserActions.addUser, (state, { user }) =>
    userAdapter.addOne(user, state)
  ),
  on(UserActions.updateUser, (state, { update }) =>
    userAdapter.updateOne(update, state)
  ),
  on(UserActions.deleteUser, (state, { id }) =>
    userAdapter.removeOne(id, state)
  )
);
```

